<?php
namespace nameSiteboosterseo;
if ( ! defined( 'ABSPATH' ) ) {
    exit;
}
class classSiteboosterseo {
    public function run() {
        add_action( 'admin_menu', [ $this, 'add_admin_menu' ] );
        add_action( 'admin_init', [ $this, 'register_settings' ] );
        add_action( 'admin_enqueue_scripts', [ $this, 'enqueue_admin_styles' ] );
        add_action( 'wp_head', [ $this, 'insert_metadata' ] );
        add_filter( 'pre_get_document_title', [ $this, 'custom_title' ] );
    }
    //Create the plugin functions
    public function add_admin_menu() {
        add_menu_page(
            'dcjMyPlug Settings',
            'SBSEO',
            'manage_options',
            'dcjmyplug_settings',
            [ $this, 'render_settings_page' ],
            'dashicons-airplane',
            80
        );
    }
    public function register_settings() {
        register_setting(
            'dcjmyplug_settings_group',
            'dcjmyplug_options',
            [ $this, 'sanitize_callback' ]
        );
    }
    /*Sanitize de input data, secure even with nonce */
    public function sanitize_callback( $input ) {
         // security with nonce, scape slashes and sanitize
   $nonce = isset( $_POST['dcjmyplug_nonce'] ) ? sanitize_text_field(wp_unslash( $_POST['dcjmyplug_nonce'] )) : '';
if ( ! wp_verify_nonce( $nonce, 'dcjmyplug_save_metadata' ) ) {
    add_settings_error(
        'dcjmyplug_messages',
        'dcjmyplug_message',
        'Security check failed. Please try again.',
        'error'
    );
    return [];
}
/*sanitizing with limit of charts */
        $new_input = [];
        if ( ! empty( $input['title'] ) ) {
            $new_input['title'] = mb_substr( sanitize_text_field( $input['title'] ), 0, 60 );
        }
        if ( ! empty( $input['description'] ) ) {
            $new_input['description'] = mb_substr( sanitize_textarea_field( $input['description'] ), 0, 160 );
        }
        if ( ! empty( $input['keywords'] ) ) {
            $new_input['keywords'] = mb_substr( sanitize_text_field( $input['keywords'] ), 0, 200 );
        }
        if ( empty( $new_input ) ) {
            add_settings_error( 'dcjmyplug_messages', 'dcjmyplug_message', 'Please fill at least one field.', 'error' );
        } else {
            add_settings_error( 'dcjmyplug_messages', 'dcjmyplug_message', 'Metadata has been successfully inserted.', 'updated' );
        }
        return $new_input;
    }
    /*Slyling the plugin page */
    public function enqueue_admin_styles( $hook ) {
        if ( $hook !== 'toplevel_page_dcjmyplug_settings' ) {
            return;
        }
        $css_path = plugin_dir_path( dirname( __FILE__ ) ) . 'assets/css/siteboosterseo.admin.css';
        $css_url = plugins_url( 'assets/css/siteboosterseo.admin.css', dirname( __FILE__ ) );
        $version = '1.2.0';
        wp_enqueue_style( 'dcjmyplug_admin_css', $css_url, [], $version, 'all' );
    }
    /*Display the plugin admin page */
    public function render_settings_page() {
        if (!current_user_can( 'manage_options' ) ) {
            return;
        }
        $options = get_option( 'dcjmyplug_options' );
