    public function insert_metadata() {
        $options = get_option( 'dcjmyplug_options' );
        if ( empty( $options ) ) {
            return;
        }
        if ( ! empty( $options['description'] ) ) {
            echo '<meta name="description" content="' . esc_attr( $options['description'] ) . '">' . "\n";
        }

        if ( ! empty( $options['keywords'] ) ) {
            echo '<meta name="keywords" content="' . esc_attr( $options['keywords'] ) . '">' . "\n";
        }
    }
    public function custom_title( $title ) {
        $options = get_option( 'dcjmyplug_options' );
        return !empty( $options['title'] ) ? $options['title'] : $title;
    }
